#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

// Function to calculate the number of ways to decompose the tree into paths
long long calculateWays(int *A, int **edges, int N) {
    long long *dp = (long long *)malloc(N * sizeof(long long));
    // Initialize dp array
    for (int i = 0; i < N; i++) {
        dp[i] = 1;
    }
    // Calculate the number of ways to decompose the tree into paths
    for (int i = 0; i < N; i++) {
        int sum = A[i];
        for (int j = 0; j < N - 1; j++) {
            if (edges[j][0] == i || edges[j][1] == i) {
                sum += A[edges[j][0] == i ? edges[j][1] : edges[j][0]];
            }
        }
        if (sum >= 0) {
            dp[i] = (dp[i] * (sum + 1)) % MOD;
        }
    }
    long long result = dp[0];
    free(dp);
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int *A = (int *)malloc(N * sizeof(int));
        int **edges = (int **)malloc((N - 1) * sizeof(int *));
        for (int i = 0; i < N - 1; i++) {
            edges[i] = (int *)malloc(2 * sizeof(int));
        }
        // Read input
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < N - 1; i++) {
            scanf("%d %d", &edges[i][0], &edges[i][1]);
        }
        // Calculate and print the result
        printf("%lld\n", calculateWays(A, edges, N));
        free(A);
        for (int i = 0; i < N - 1; i++) {
            free(edges[i]);
        }
        free(edges);
    }
    return 0;
}

