// Function to calculate the number of ways to decompose the tree into paths
long long calculateWays(vector<int> &A, vector<pair<int, int>> &edges, int N) {
    vector<long long> dp(N, 1);
    // Calculate the number of ways to decompose the tree into paths
    for (int i = 0; i < N; i++) {
        int sum = A[i];
        for (int j = 0; j < N - 1; j++) {
            if (edges[j].first == i || edges[j].second == i) {
                sum += A[edges[j].first == i ? edges[j].second : edges[j].first];
            }
        }
        if (sum >= 0) {
            dp[i] = (dp[i] * (sum + 1)) % MOD;
        }
    }
    return dp[0];
}

